import { useEffect, useState, useCallback, useMemo } from 'react';
import axios from 'axios';
import {
  AreaChart, Area, LineChart, Line,
  ResponsiveContainer, Tooltip as ReTooltip,
  XAxis, YAxis, CartesianGrid, Legend,
} from 'recharts';

const API = process.env.REACT_APP_API_URL || 'http://localhost:8000';

/* ─────────────────────────────────────────────────────────────────────────
   METRIC DEFINITIONS — must match what collector.py stores in the DB
   ───────────────────────────────────────────────────────────────────────── */
const METRICS = {
  'CPU Used %':      { key: 'cpu_used_pct',      unit: '%',     color: '#00d4ff' },
  'Memory Used %':   { key: 'memory_used_pct',   unit: '%',     color: '#9b8fff' },
  'Load (1m)':       { key: 'load_one',           unit: '',      color: '#4ade80' },
  'Load (5m)':       { key: 'load_five',          unit: '',      color: '#a3e635' },
  'Net RX (B/s)':    { key: 'net_rx_bytes',       unit: 'B/s',   color: '#ffb347' },
  'Net TX (B/s)':    { key: 'net_tx_bytes',       unit: 'B/s',   color: '#ff6b35' },
  'Disk Used %':     { key: 'disk_used_pct',      unit: '%',     color: '#f7e25a' },
  'CPU Idle %':      { key: 'cpu_idle_pct',       unit: '%',     color: '#34d399' },
};

/* 20 distinct Ganglia-style colours for per-node cluster chart */
const NODE_COLORS = [
  '#00d4ff','#9b8fff','#4ade80','#ffb347','#ff6b35',
  '#f7e25a','#ff4757','#a3e635','#e879f9','#38bdf8',
  '#fb923c','#34d399','#f472b6','#818cf8','#facc15',
  '#22d3ee','#c084fc','#86efac','#fda4af','#67e8f9',
];

/* ─────────────────────── Helpers ─────────────────────── */
const fmtTime = (iso) => {
  if (!iso) return '—';
  return new Date(iso).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
};
const fmtDate = (iso) => {
  if (!iso) return '—';
  return new Date(iso).toLocaleString([], { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' });
};
const timeAgo = (iso) => {
  if (!iso) return '—';
  const diff = (Date.now() - new Date(iso).getTime()) / 1000;
  if (diff < 60)   return `${Math.round(diff)}s ago`;
  if (diff < 3600) return `${Math.round(diff / 60)}m ago`;
  return `${Math.round(diff / 3600)}h ago`;
};
const fmtBytes = (v) => {
  if (v == null) return '—';
  if (v < 1024)       return `${v.toFixed(0)} B/s`;
  if (v < 1048576)    return `${(v/1024).toFixed(1)} KB/s`;
  return `${(v/1048576).toFixed(1)} MB/s`;
};

const severityColor = (s) => {
  const m = { Critical:'#ff4757', High:'#ff6b35', Medium:'#ffb347', Low:'#f7e25a', Normal:'#4ade80' };
  return m[s] || '#4ade80';
};

const nodeStatusColor = (node) => {
  if (node.active_anomalies > 0) return severityColor(node.latest_anomaly?.severity);
  if (node.status === 'critical') return '#ff4757';
  if (node.status === 'warning')  return '#ffb347';
  if (node.status === 'online')   return '#4ade80';
  return '#6c757d';
};

/* Get latest value for a metric from node.latest_metrics */
const latestVal = (node, metricKey) => {
  const m = node.latest_metrics?.find(x => x.metric_name === metricKey);
  return m ? m.value : null;
};

/* ─────────────────────── Mini Gauge Bar ─────────────────────── */
function GaugeBar({ value, max = 100, color = '#00d4ff', width = '100%' }) {
  const pct = Math.min(100, Math.max(0, (value / max) * 100));
  return (
    <div style={{ width, height: 4, background: 'rgba(255,255,255,0.08)', borderRadius: 2, overflow: 'hidden' }}>
      <div style={{ width: `${pct}%`, height: '100%', background: color, borderRadius: 2, transition: 'width 0.4s ease' }} />
    </div>
  );
}

/* ─────────────────────── Sparkline ─────────────────────── */
function Sparkline({ data = [], color = '#00d4ff', height = 36 }) {
  if (!data || data.length < 2) {
    return (
      <div style={{ height, display: 'flex', alignItems: 'center', color: '#333', fontSize: 10 }}>
        No data
      </div>
    );
  }
  const pts = data.map((d, i) => ({ i, v: typeof d === 'object' ? d.value : d }));
  return (
    <ResponsiveContainer width="100%" height={height}>
      <AreaChart data={pts} margin={{ top: 1, right: 0, left: 0, bottom: 1 }}>
        <defs>
          <linearGradient id={`sg-${color.replace('#','')}`} x1="0" y1="0" x2="0" y2="1">
            <stop offset="5%"  stopColor={color} stopOpacity={0.35} />
            <stop offset="95%" stopColor={color} stopOpacity={0} />
          </linearGradient>
        </defs>
        <Area
          type="monotone" dataKey="v"
          stroke={color} strokeWidth={1.5}
          fill={`url(#sg-${color.replace('#','')})`}
          dot={false} isAnimationActive={false}
        />
      </AreaChart>
    </ResponsiveContainer>
  );
}

/* ─────────────────────── Stat Pill ─────────────────────── */
function StatPill({ label, value, color = '#00d4ff', icon }) {
  return (
    <div style={{
      background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.08)',
      borderRadius: 12, padding: '10px 18px', minWidth: 110, flex: '1 1 110px',
      display: 'flex', flexDirection: 'column', gap: 4, backdropFilter: 'blur(8px)',
    }}>
      <div style={{ fontSize: 11, color: '#888', letterSpacing: 1, textTransform: 'uppercase' }}>
        {icon} {label}
      </div>
      <div style={{ fontSize: 24, fontWeight: 700, color, lineHeight: 1 }}>{value ?? '—'}</div>
    </div>
  );
}

/* ─────────────────────── Cluster Overview Chart (Ganglia-style) ─────────── */
function ClusterOverviewChart({ rawHistory, allNodes, metricLabel, metricUnit }) {
  /* Pivot [{hostname, timestamp, value}] → [{time, node1: v, node2: v, ...}] */
  const { chartData, hostnames } = useMemo(() => {
    if (!rawHistory || rawHistory.length === 0) return { chartData: [], hostnames: [] };
    const hosts = [...new Set(rawHistory.map(r => r.hostname))].sort();
    const timeMap = new Map();
    for (const row of rawHistory) {
      const t = new Date(row.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
      if (!timeMap.has(t)) timeMap.set(t, { time: t });
      const existing = timeMap.get(t)[row.hostname];
      // keep latest value per (time-bucket, host)
      if (existing === undefined || row.timestamp > (timeMap.get(t).__ts || '')) {
        timeMap.get(t)[row.hostname] = parseFloat(row.value.toFixed(2));
        timeMap.get(t).__ts = row.timestamp;
      }
    }
    const data = Array.from(timeMap.values())
      .map(({ __ts, ...rest }) => rest)
      .sort((a, b) => a.time.localeCompare(b.time));
    return { chartData: data, hostnames: hosts };
  }, [rawHistory]);

  if (chartData.length === 0) {
    return (
      <div style={{
        height: 160, display: 'flex', alignItems: 'center', justifyContent: 'center',
        color: '#444', fontSize: 13, background: 'rgba(255,255,255,0.02)', borderRadius: 12,
      }}>
        No history data yet — waiting for first collection cycle…
      </div>
    );
  }

  return (
    <ResponsiveContainer width="100%" height={180}>
      <AreaChart data={chartData} margin={{ top: 4, right: 12, left: 0, bottom: 4 }}>
        <defs>
          {hostnames.map((h, i) => (
            <linearGradient key={h} id={`cg-${i}`} x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%"  stopColor={NODE_COLORS[i % NODE_COLORS.length]} stopOpacity={0.45} />
              <stop offset="95%" stopColor={NODE_COLORS[i % NODE_COLORS.length]} stopOpacity={0.05} />
            </linearGradient>
          ))}
        </defs>
        <CartesianGrid stroke="rgba(255,255,255,0.04)" strokeDasharray="3 3" />
        <XAxis dataKey="time" tick={{ fill: '#555', fontSize: 10 }} interval="preserveStartEnd" />
        <YAxis tick={{ fill: '#555', fontSize: 10 }} width={36}
          tickFormatter={v => metricUnit === '%' ? `${v}%` : v} />
        <ReTooltip
          contentStyle={{ background: '#0d1117', border: '1px solid rgba(255,255,255,0.1)', borderRadius: 8, fontSize: 11 }}
          formatter={(val, name) => [`${val}${metricUnit}`, name]}
        />
        <Legend wrapperStyle={{ fontSize: 11, color: '#888' }} />
        {hostnames.map((h, i) => (
          <Area
            key={h} type="monotone" dataKey={h}
            stackId="1"
            stroke={NODE_COLORS[i % NODE_COLORS.length]}
            fill={`url(#cg-${i})`}
            strokeWidth={1.5}
            dot={false} isAnimationActive={false}
          />
        ))}
      </AreaChart>
    </ResponsiveContainer>
  );
}

/* ─────────────────────── Node Card ─────────────────────── */
function NodeCard({ node, onClick }) {
  const borderColor = nodeStatusColor(node);
  const hasAnomaly  = node.active_anomalies > 0;

  const cpu  = latestVal(node, 'cpu_used_pct');
  const mem  = latestVal(node, 'memory_used_pct');
  const load = latestVal(node, 'load_one');
  const disk = latestVal(node, 'disk_used_pct');

  const cpuColor  = cpu  != null ? (cpu  > 80 ? '#ff4757' : cpu  > 60 ? '#ffb347' : '#4ade80') : '#555';
  const memColor  = mem  != null ? (mem  > 85 ? '#ff4757' : mem  > 70 ? '#ffb347' : '#9b8fff') : '#555';

  return (
    <div
      className="node-card"
      onClick={() => onClick(node)}
      style={{
        position: 'relative', cursor: 'pointer',
        background: hasAnomaly ? `rgba(255,71,87,0.04)` : 'rgba(255,255,255,0.03)',
        border: `1px solid ${borderColor}30`,
        borderLeft: `3px solid ${borderColor}`,
        borderRadius: 14, padding: '14px 16px',
        backdropFilter: 'blur(12px)',
        transition: 'transform 0.18s ease, box-shadow 0.18s ease',
        boxShadow: hasAnomaly
          ? `0 0 20px ${borderColor}25, 0 2px 12px rgba(0,0,0,0.4)`
          : '0 2px 12px rgba(0,0,0,0.3)',
      }}
      onMouseEnter={e => {
        e.currentTarget.style.transform = 'translateY(-3px)';
        e.currentTarget.style.boxShadow = `0 8px 28px ${borderColor}35, 0 4px 16px rgba(0,0,0,0.5)`;
      }}
      onMouseLeave={e => {
        e.currentTarget.style.transform = 'translateY(0)';
        e.currentTarget.style.boxShadow = hasAnomaly
          ? `0 0 20px ${borderColor}25, 0 2px 12px rgba(0,0,0,0.4)`
          : '0 2px 12px rgba(0,0,0,0.3)';
      }}
    >
      {/* Pulse ring for anomaly */}
      {hasAnomaly && (
        <span style={{
          position: 'absolute', top: 10, right: 10,
          width: 8, height: 8, borderRadius: '50%',
          background: borderColor, color: borderColor,
          animation: 'pulse 1.6s ease-out infinite',
        }} />
      )}

      {/* Header row */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 10 }}>
        <div>
          <div style={{ fontWeight: 700, fontSize: 13, color: '#e8eaf0', letterSpacing: 0.3, fontFamily: 'monospace' }}>
            {node.hostname}
          </div>
          <div style={{ fontSize: 10, color: '#555', marginTop: 1 }}>{node.ip_address || '—'}</div>
        </div>
        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 4 }}>
          <div style={{
            fontSize: 10, fontWeight: 700, padding: '2px 8px', borderRadius: 99,
            background: `${borderColor}20`, color: borderColor,
            letterSpacing: 0.5, textTransform: 'uppercase',
          }}>
            {node.status || 'unknown'}
          </div>
          {node.active_users > 0 && (
            <div style={{ fontSize: 10, color: '#9b8fff' }}>👤 {node.active_users}</div>
          )}
        </div>
      </div>

      {/* Metric summary row */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '4px 10px', marginBottom: 10 }}>
        {cpu != null && (
          <div>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 3 }}>
              <span style={{ fontSize: 10, color: '#666' }}>CPU</span>
              <span style={{ fontSize: 11, fontWeight: 700, color: cpuColor }}>{cpu.toFixed(1)}%</span>
            </div>
            <GaugeBar value={cpu} color={cpuColor} />
          </div>
        )}
        {mem != null && (
          <div>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 3 }}>
              <span style={{ fontSize: 10, color: '#666' }}>MEM</span>
              <span style={{ fontSize: 11, fontWeight: 700, color: memColor }}>{mem.toFixed(1)}%</span>
            </div>
            <GaugeBar value={mem} color={memColor} />
          </div>
        )}
        {load != null && (
          <div>
            <span style={{ fontSize: 10, color: '#666' }}>Load </span>
            <span style={{ fontSize: 11, fontWeight: 700, color: '#4ade80' }}>{load.toFixed(2)}</span>
          </div>
        )}
        {disk != null && (
          <div>
            <span style={{ fontSize: 10, color: '#666' }}>Disk </span>
            <span style={{ fontSize: 11, fontWeight: 700, color: disk > 85 ? '#ff4757' : '#f7e25a' }}>{disk.toFixed(1)}%</span>
          </div>
        )}
      </div>

      {/* Sparklines: CPU + Memory + Load */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
          <span style={{ fontSize: 9, color: '#00d4ff', width: 24, flexShrink: 0 }}>CPU</span>
          <div style={{ flex: 1 }}>
            <Sparkline data={node.sparklines?.cpu_used_pct} color="#00d4ff" height={28} />
          </div>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
          <span style={{ fontSize: 9, color: '#9b8fff', width: 24, flexShrink: 0 }}>MEM</span>
          <div style={{ flex: 1 }}>
            <Sparkline data={node.sparklines?.memory_used_pct} color="#9b8fff" height={28} />
          </div>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
          <span style={{ fontSize: 9, color: '#4ade80', width: 24, flexShrink: 0 }}>LD</span>
          <div style={{ flex: 1 }}>
            <Sparkline data={node.sparklines?.load_one} color="#4ade80" height={28} />
          </div>
        </div>
      </div>

      {/* Anomaly badge */}
      {hasAnomaly && (
        <div style={{
          marginTop: 10, padding: '5px 10px', borderRadius: 8,
          background: `${borderColor}12`, border: `1px solid ${borderColor}35`,
          fontSize: 10, color: borderColor, lineHeight: 1.4,
        }}>
          🚨 <strong>{node.active_anomalies} anomal{node.active_anomalies > 1 ? 'ies' : 'y'}</strong>
          {node.latest_anomaly?.severity && ` — ${node.latest_anomaly.severity}`}
          {node.latest_anomaly?.description && (
            <div style={{ marginTop: 2, color: '#bbb', fontSize: 9 }}
              title={node.latest_anomaly.description}>
              {node.latest_anomaly.description.slice(0, 55)}…
            </div>
          )}
        </div>
      )}
    </div>
  );
}

/* ─────────────────────── Anomaly Feed ─────────────────────── */
function AnomalyFeed({ feed }) {
  return (
    <div style={{
      background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)',
      borderRadius: 16, padding: '16px', backdropFilter: 'blur(10px)',
      display: 'flex', flexDirection: 'column', gap: 0,
    }}>
      <div style={{ fontWeight: 700, fontSize: 13, color: '#e8eaf0', marginBottom: 12, letterSpacing: 0.5 }}>
        🔔 Live Anomaly Feed
      </div>
      <div style={{ overflowY: 'auto', maxHeight: 'calc(100vh - 380px)', display: 'flex', flexDirection: 'column', gap: 8 }}>
        {feed.length === 0 && (
          <div style={{ color: '#4ade80', fontSize: 12, padding: 8 }}>✅ No active anomalies</div>
        )}
        {feed.map((ev) => {
          const sc = severityColor(ev.severity);
          return (
            <div key={ev.id} style={{
              padding: '8px 10px', borderRadius: 10,
              background: `${sc}08`, borderLeft: `2px solid ${sc}`,
              fontSize: 11, lineHeight: 1.5,
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 2 }}>
                <span style={{ fontWeight: 700, color: sc }}>{ev.severity}</span>
                <span style={{ color: '#555', fontSize: 10 }}>{timeAgo(ev.detected_at)}</span>
              </div>
              <div style={{ color: '#bbb', fontWeight: 600, fontFamily: 'monospace' }}>{ev.hostname}</div>
              <div style={{ color: '#888' }}>{ev.metric_name?.replace(/_/g, ' ')}</div>
              <div style={{ color: '#666', fontSize: 10 }}>{ev.description?.slice(0, 70)}</div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

/* ─────────────────────── Node Drilldown Modal ─────────────────────── */
function DrilldownModal({ node, onClose }) {
  const [anomalies, setAnomalies] = useState([]);
  const [metrics,   setMetrics]   = useState([]);
  const [tab, setTab] = useState('overview');

  useEffect(() => {
    if (!node) return;
    const id = node.id;
    axios.get(`${API}/api/cluster/node/${id}/anomalies?limit=30`).then(r => setAnomalies(r.data)).catch(() => {});
    axios.get(`${API}/api/cluster/node/${id}/metrics?limit=200`).then(r => setMetrics(r.data)).catch(() => {});
  }, [node]);

  if (!node) return null;

  /* Group metrics by name and build chart-ready arrays (time-ascending) */
  const metricGroups = useMemo(() => {
    const groups = {};
    for (const m of metrics) {
      if (!groups[m.metric_name]) groups[m.metric_name] = [];
      groups[m.metric_name].push({
        time: new Date(m.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        value: parseFloat((m.value || 0).toFixed(3)),
      });
    }
    // Each group is already desc-ordered from the API; reverse to get asc
    for (const k of Object.keys(groups)) groups[k] = groups[k].reverse();
    return groups;
  }, [metrics]);

  const chartMetrics = Object.keys(metricGroups);
  const metricColors = ['#00d4ff','#9b8fff','#4ade80','#ffb347','#ff6b35','#f7e25a','#ff4757','#34d399'];
  const tabs = ['overview', 'metrics', 'anomalies'];
  const statusColor = nodeStatusColor(node);

  return (
    <div style={{
      position: 'fixed', inset: 0, zIndex: 1000,
      background: 'rgba(0,0,0,0.78)', backdropFilter: 'blur(6px)',
      display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 24,
    }} onClick={onClose}>
      <div style={{
        background: '#0d1117', border: '1px solid rgba(255,255,255,0.1)',
        borderRadius: 20, width: '100%', maxWidth: 900,
        maxHeight: '90vh', overflow: 'hidden', display: 'flex', flexDirection: 'column',
        boxShadow: '0 24px 80px rgba(0,0,0,0.8)',
      }} onClick={e => e.stopPropagation()}>

        {/* Modal Header */}
        <div style={{
          padding: '20px 24px', borderBottom: '1px solid rgba(255,255,255,0.06)',
          display: 'flex', justifyContent: 'space-between', alignItems: 'center',
          background: `${statusColor}06`,
        }}>
          <div>
            <div style={{ fontSize: 18, fontWeight: 800, color: '#e8eaf0', letterSpacing: 0.5 }}>
              🖥️ {node.hostname}
            </div>
            <div style={{ fontSize: 12, color: '#888', marginTop: 2 }}>
              {node.ip_address} · {node.os_version || 'Linux'} · {node.architecture || 'x86_64'}
            </div>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
            <div style={{
              padding: '4px 12px', borderRadius: 99, fontSize: 11, fontWeight: 700,
              background: `${statusColor}20`, color: statusColor,
              textTransform: 'uppercase', letterSpacing: 0.5,
            }}>
              {node.status || 'unknown'}
            </div>
            <button onClick={onClose} style={{
              background: 'rgba(255,255,255,0.07)', border: '1px solid rgba(255,255,255,0.1)',
              color: '#aaa', borderRadius: 8, padding: '6px 14px', cursor: 'pointer', fontSize: 13,
            }}>✕ Close</button>
          </div>
        </div>

        {/* Tab bar */}
        <div style={{ display: 'flex', borderBottom: '1px solid rgba(255,255,255,0.06)', padding: '0 24px' }}>
          {tabs.map(t => (
            <button key={t} onClick={() => setTab(t)} style={{
              background: 'none', border: 'none', cursor: 'pointer',
              padding: '12px 16px', fontSize: 12, fontWeight: 600,
              color: tab === t ? '#00d4ff' : '#666',
              borderBottom: tab === t ? '2px solid #00d4ff' : '2px solid transparent',
              textTransform: 'capitalize', letterSpacing: 0.5, transition: 'color 0.15s',
            }}>{t}</button>
          ))}
        </div>

        {/* Modal Body */}
        <div style={{ flex: 1, overflowY: 'auto', padding: '20px 24px' }}>

          {/* ── Overview Tab ── */}
          {tab === 'overview' && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
              {/* Stat pills */}
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 10 }}>
                {[
                  { label: 'Anomalies',      value: node.active_anomalies,  color: node.active_anomalies > 0 ? '#ff4757' : '#4ade80', icon: '🚨' },
                  { label: 'CPU Used',       value: latestVal(node,'cpu_used_pct') != null ? `${latestVal(node,'cpu_used_pct').toFixed(1)}%` : '—', color: '#00d4ff', icon: '🔲' },
                  { label: 'Mem Used',       value: latestVal(node,'memory_used_pct') != null ? `${latestVal(node,'memory_used_pct').toFixed(1)}%` : '—', color: '#9b8fff', icon: '💾' },
                  { label: 'Load (1m)',      value: latestVal(node,'load_one') != null ? latestVal(node,'load_one').toFixed(2) : '—', color: '#4ade80', icon: '📈' },
                  { label: 'Net RX',         value: latestVal(node,'net_rx_bytes') != null ? fmtBytes(latestVal(node,'net_rx_bytes')) : '—', color: '#ffb347', icon: '📡' },
                  { label: 'Disk Used',      value: latestVal(node,'disk_used_pct') != null ? `${latestVal(node,'disk_used_pct').toFixed(1)}%` : '—', color: '#f7e25a', icon: '💿' },
                ].map(p => <StatPill key={p.label} {...p} />)}
              </div>

              {/* (User sessions and processes are not collected — would require
                  SSH / node_exporter process endpoint on each node) */}

            </div>
          )}

          {/* ── Metrics Tab ── */}
          {tab === 'metrics' && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 20 }}>
              {chartMetrics.length === 0 && <div style={{ color: '#555', fontSize: 13 }}>No metric history yet.</div>}
              {/* Group metrics in pairs for 2-column layout */}
              {Array.from({ length: Math.ceil(chartMetrics.length / 2) }, (_, gi) => (
                <div key={gi} style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 14 }}>
                  {chartMetrics.slice(gi * 2, gi * 2 + 2).map((name, li) => {
                    const idx = gi * 2 + li;
                    const color = metricColors[idx % metricColors.length];
                    const data = metricGroups[name];
                    return (
                      <div key={name} style={{ background: 'rgba(255,255,255,0.03)', borderRadius: 12, padding: 14 }}>
                        <div style={{ fontSize: 11, fontWeight: 700, color, marginBottom: 8, textTransform: 'uppercase', letterSpacing: 0.7 }}>
                          {name.replace(/_/g, ' ')}
                        </div>
                        <ResponsiveContainer width="100%" height={110}>
                          <AreaChart data={data}>
                            <defs>
                              <linearGradient id={`md-${idx}`} x1="0" y1="0" x2="0" y2="1">
                                <stop offset="5%"  stopColor={color} stopOpacity={0.3} />
                                <stop offset="95%" stopColor={color} stopOpacity={0} />
                              </linearGradient>
                            </defs>
                            <CartesianGrid stroke="rgba(255,255,255,0.04)" strokeDasharray="3 3" />
                            <XAxis dataKey="time" tick={{ fill: '#555', fontSize: 9 }} interval="preserveStartEnd" />
                            <YAxis tick={{ fill: '#555', fontSize: 9 }} width={34} />
                            <ReTooltip contentStyle={{ background: '#111', border: `1px solid ${color}40`, borderRadius: 8, fontSize: 11 }} />
                            <Area type="monotone" dataKey="value" stroke={color} strokeWidth={1.5}
                              fill={`url(#md-${idx})`} dot={false} />
                          </AreaChart>
                        </ResponsiveContainer>
                      </div>
                    );
                  })}
                </div>
              ))}
            </div>
          )}

          {/* ── Anomalies Tab ── */}
          {tab === 'anomalies' && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
              {anomalies.length === 0 && <div style={{ color: '#4ade80', fontSize: 13 }}>✅ No anomalies for this node.</div>}
              {anomalies.map(ev => {
                const sc = severityColor(ev.severity);
                return (
                  <div key={ev.id} style={{
                    padding: '12px 14px', borderRadius: 10,
                    background: `${sc}08`, border: `1px solid ${sc}25`, borderLeft: `3px solid ${sc}`,
                  }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6 }}>
                      <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
                        <span style={{ fontWeight: 700, fontSize: 12, color: sc }}>{ev.severity}</span>
                        <span style={{ fontSize: 11, color: '#888', background: 'rgba(255,255,255,0.06)', padding: '1px 7px', borderRadius: 5 }}>{ev.detector}</span>
                        <span style={{ fontSize: 11, color: '#666' }}>score: {ev.anomaly_score?.toFixed(3)}</span>
                      </div>
                      <span style={{ fontSize: 11, color: '#555' }}>{fmtDate(ev.detected_at)}</span>
                    </div>
                    <div style={{ fontSize: 11, color: '#aaa', marginBottom: 4 }}>
                      <strong style={{ color: '#ccc' }}>{ev.metric_name?.replace(/_/g, ' ')}</strong>
                      {ev.metric_value != null && ` — ${ev.metric_value.toFixed(2)}`}
                    </div>
                    <div style={{ fontSize: 11, color: '#888' }}>{ev.description}</div>
                    {ev.resolved && <div style={{ fontSize: 10, color: '#4ade80', marginTop: 4 }}>✓ Resolved</div>}
                  </div>
                );
              })}
            </div>
          )}

        </div>
      </div>
    </div>
  );
}

/* ─────────────────────────────────────────────────────────────────────────
   Main App
   ───────────────────────────────────────────────────────────────────────── */
export default function App() {
  const [overview,      setOverview]      = useState(null);
  const [nodes,         setNodes]         = useState([]);
  const [feed,          setFeed]          = useState([]);
  const [history,       setHistory]       = useState([]);
  const [selectedNode,  setSelectedNode]  = useState(null);
  const [now,           setNow]           = useState(new Date());
  const [lastRefresh,   setLastRefresh]   = useState(null);
  const [filterStatus,  setFilterStatus]  = useState('all');
  const [chartMetric,   setChartMetric]   = useState('CPU Used %');
  const [historyHours,  setHistoryHours]  = useState(1);

  const currentMetricDef = METRICS[chartMetric];

  const fetchHistory = useCallback((metricKey, hours) => {
    axios.get(`${API}/api/cluster/history?metric=${metricKey}&hours=${hours}`)
      .then(r => setHistory(r.data))
      .catch(() => {});
  }, []);

  const fetchAll = useCallback(() => {
    axios.get(`${API}/api/cluster/overview`).then(r => setOverview(r.data)).catch(() => {});
    axios.get(`${API}/api/cluster/nodes`).then(r => setNodes(r.data)).catch(() => {});
    axios.get(`${API}/api/cluster/anomaly-feed?limit=60`).then(r => setFeed(r.data)).catch(() => {});
    fetchHistory(currentMetricDef.key, historyHours);
    setLastRefresh(new Date());
  }, [fetchHistory, currentMetricDef.key, historyHours]);

  useEffect(() => {
    fetchAll();
    const iv1 = setInterval(fetchAll, 30000);
    const iv2 = setInterval(() => setNow(new Date()), 1000);
    return () => { clearInterval(iv1); clearInterval(iv2); };
  }, [fetchAll]);

  /* When chart metric or hours changes, refetch history immediately */
  useEffect(() => {
    fetchHistory(currentMetricDef.key, historyHours);
  }, [chartMetric, historyHours, fetchHistory, currentMetricDef.key]);

  const filtered = nodes.filter(n => {
    if (filterStatus === 'all')     return true;
    if (filterStatus === 'anomaly') return n.active_anomalies > 0;
    return n.status === filterStatus;
  });

  const statusFilters = [
    { key: 'all',      label: 'All Nodes' },
    { key: 'online',   label: '🟢 Online' },
    { key: 'anomaly',  label: '🔴 Anomaly' },
    { key: 'warning',  label: '🟡 Warning' },
    { key: 'critical', label: '🔴 Critical' },
    { key: 'offline',  label: '⚫ Offline' },
  ];

  return (
    <div style={{
      minHeight: '100vh', background: '#080c14',
      fontFamily: "'Inter', -apple-system, BlinkMacSystemFont, sans-serif",
      color: '#e8eaf0',
    }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&display=swap');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        ::-webkit-scrollbar { width: 6px; height: 6px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.12); border-radius: 3px; }
        @keyframes pulse {
          0%   { box-shadow: 0 0 0 0 currentColor; opacity: 1; }
          70%  { box-shadow: 0 0 0 8px transparent; opacity: 0.4; }
          100% { box-shadow: 0 0 0 0 transparent; opacity: 1; }
        }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(6px); } to { opacity: 1; transform: none; } }
        .node-card { animation: fadeIn 0.3s ease both; }
        select option { background: #0d1117; }
      `}</style>

      {/* ── Top Bar ── */}
      <div style={{
        position: 'sticky', top: 0, zIndex: 100,
        background: 'rgba(8,12,20,0.94)', backdropFilter: 'blur(16px)',
        borderBottom: '1px solid rgba(255,255,255,0.06)',
        padding: '0 28px', display: 'flex', alignItems: 'center',
        justifyContent: 'space-between', height: 56,
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 14 }}>
          <div style={{
            width: 32, height: 32, borderRadius: 8,
            background: 'linear-gradient(135deg, #00d4ff, #0055ff)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontSize: 17,
          }}>⛽</div>
          <div>
            <div style={{ fontWeight: 800, fontSize: 15, letterSpacing: 0.5 }}>ONGC AI Cluster Monitor</div>
            <div style={{ fontSize: 10, color: '#555', letterSpacing: 0.5 }}>GANGLIA-STYLE HPC DASHBOARD</div>
          </div>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 18 }}>
          {overview?.active_anomalies > 0 && (
            <div style={{
              display: 'flex', alignItems: 'center', gap: 6,
              background: 'rgba(255,71,87,0.15)', border: '1px solid rgba(255,71,87,0.3)',
              borderRadius: 8, padding: '4px 12px', fontSize: 11, color: '#ff4757', fontWeight: 700,
              animation: 'pulse 2s infinite',
            }}>
              🚨 {overview.active_anomalies} ANOMAL{overview.active_anomalies > 1 ? 'IES' : 'Y'} ACTIVE
            </div>
          )}
          <div style={{ fontSize: 12, color: '#555', fontFamily: 'monospace' }}>
            {now.toLocaleTimeString()}
          </div>
          <button onClick={fetchAll} style={{
            background: 'rgba(0,212,255,0.1)', border: '1px solid rgba(0,212,255,0.3)',
            color: '#00d4ff', borderRadius: 8, padding: '6px 14px', cursor: 'pointer',
            fontSize: 12, fontWeight: 600,
          }}>↺ Refresh</button>
        </div>
      </div>

      <div style={{ padding: '22px 28px', display: 'flex', flexDirection: 'column', gap: 20 }}>

        {/* ── Summary Strip ── */}
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 10 }}>
          <StatPill label="Total Nodes"    value={overview?.total_nodes}      color="#00d4ff" icon="🖥️" />
          <StatPill label="Online"         value={overview?.healthy_nodes}    color="#4ade80" icon="✅" />
          <StatPill label="Warnings"       value={overview?.warnings}         color="#ffb347" icon="⚠️" />
          <StatPill label="Critical"       value={overview?.critical}         color="#ff4757" icon="🔴" />
          <StatPill label="Offline"        value={overview?.offline}          color="#6c757d" icon="⚫" />
          <StatPill label="Active Alerts"  value={overview?.active_alerts}    color="#9b8fff" icon="🔔" />
          <StatPill label="Anomalies"      value={overview?.active_anomalies} color={overview?.active_anomalies > 0 ? '#ff4757' : '#4ade80'} icon="🚨" />
          <StatPill label="Incidents"      value={overview?.active_incidents} color="#ff6b35" icon="📋" />
        </div>

        {/* ── Ganglia-style Cluster Overview Chart ── */}
        <div style={{
          background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)',
          borderRadius: 16, padding: '18px 20px', backdropFilter: 'blur(10px)',
        }}>
          {/* Chart header + controls */}
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14 }}>
            <div>
              <div style={{ fontWeight: 700, fontSize: 14, color: '#e8eaf0', letterSpacing: 0.3 }}>
                📊 Cluster Overview — {chartMetric}
              </div>
              <div style={{ fontSize: 11, color: '#555', marginTop: 2 }}>
                Stacked area · all {nodes.length} node{nodes.length !== 1 ? 's' : ''} · last {historyHours}h
              </div>
            </div>
            <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
              {/* Metric selector */}
              <select
                value={chartMetric}
                onChange={e => setChartMetric(e.target.value)}
                style={{
                  background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.12)',
                  color: '#e8eaf0', borderRadius: 8, padding: '5px 10px', fontSize: 12, cursor: 'pointer',
                  outline: 'none',
                }}
              >
                {Object.keys(METRICS).map(k => (
                  <option key={k} value={k}>{k}</option>
                ))}
              </select>
              {/* Time range selector */}
              <select
                value={historyHours}
                onChange={e => setHistoryHours(Number(e.target.value))}
                style={{
                  background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.12)',
                  color: '#e8eaf0', borderRadius: 8, padding: '5px 10px', fontSize: 12, cursor: 'pointer',
                  outline: 'none',
                }}
              >
                <option value={1}>Last 1h</option>
                <option value={3}>Last 3h</option>
                <option value={6}>Last 6h</option>
                <option value={12}>Last 12h</option>
                <option value={24}>Last 24h</option>
              </select>
            </div>
          </div>

          <ClusterOverviewChart
            rawHistory={history}
            allNodes={nodes}
            metricLabel={chartMetric}
            metricUnit={currentMetricDef.unit}
          />
        </div>

        {/* ── Filter bar ── */}
        <div style={{ display: 'flex', gap: 8, alignItems: 'center', flexWrap: 'wrap' }}>
          {statusFilters.map(f => (
            <button key={f.key} onClick={() => setFilterStatus(f.key)} style={{
              background: filterStatus === f.key ? 'rgba(0,212,255,0.15)' : 'rgba(255,255,255,0.04)',
              border: filterStatus === f.key ? '1px solid rgba(0,212,255,0.5)' : '1px solid rgba(255,255,255,0.07)',
              color: filterStatus === f.key ? '#00d4ff' : '#888',
              borderRadius: 8, padding: '5px 14px', cursor: 'pointer', fontSize: 12, fontWeight: 600,
              transition: 'all 0.15s',
            }}>{f.label}</button>
          ))}
          <div style={{ marginLeft: 'auto', fontSize: 11, color: '#555' }}>
            {filtered.length} node{filtered.length !== 1 ? 's' : ''}
            {lastRefresh && ` · Updated ${timeAgo(lastRefresh.toISOString())}`}
          </div>
        </div>

        {/* ── Main layout: Node Grid + Anomaly Feed ── */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 280px', gap: 20, alignItems: 'start' }}>

          {/* Node Grid — auto-fill scales from 3 → 20 nodes */}
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))',
            gap: 14,
          }}>
            {filtered.length === 0 && (
              <div style={{ color: '#555', fontSize: 13, gridColumn: '1/-1', padding: 20, textAlign: 'center' }}>
                {nodes.length === 0 ? '⏳ Connecting to backend…' : 'No nodes match this filter.'}
              </div>
            )}
            {filtered.map(node => (
              <div key={node.id} className="node-card">
                <NodeCard node={node} onClick={setSelectedNode} />
              </div>
            ))}
          </div>

          {/* Anomaly Feed — sticky sidebar */}
          <div style={{ position: 'sticky', top: 72 }}>
            <AnomalyFeed feed={feed} />
          </div>
        </div>

      </div>

      {/* ── Node Drilldown Modal ── */}
      {selectedNode && (
        <DrilldownModal
          node={selectedNode}
          onClose={() => setSelectedNode(null)}
        />
      )}
    </div>
  );
}
